def task_func(products, n_samples=100, sales_lower=50, sales_upper=200, profit_margin_min=0.1, profit_margin_max=0.5, random_seed=42):
    if not isinstance(products, list) or not all(isinstance(p, str) for p in products):
        raise TypeError("products must be a list of strings.")
    if not isinstance(n_samples, int) or n_samples <= 0:
        raise ValueError("n_samples must be a positive integer.")
    if not (isinstance(sales_lower, (int, float)) and isinstance(sales_upper, (int, float))):
        raise TypeError("sales_lower and sales_upper must be numeric.")
    if not (isinstance(profit_margin_min, (int, float)) and isinstance(profit_margin_max, (int, float))):
        raise TypeError("profit_margin_min and profit_margin_max must be numeric.")
    if sales_lower > sales_upper:
        raise ValueError("sales_lower cannot be greater than sales_upper.")
    if profit_margin_min > profit_margin_max:
        raise ValueError("profit_margin_min cannot be greater than profit_margin_max.")

    np.random.seed(random_seed)

    data = []
    for _ in range(n_samples):
        product = np.random.choice(products)
        sales = np.random.uniform(sales_lower, sales_upper)
        profit_margin = np.random.uniform(profit_margin_min, profit_margin_max)
        profit = sales * profit_margin
        data.append({"Product": product, "Sales": sales, "Profit": profit})

    df = pd.DataFrame(data)

    aggregated = df.groupby("Product").agg(
        Total_Sales=("Sales", "sum"),
        Total_Profit=("Profit", "sum")
    ).reset_index()

    aggregated = aggregated.sort_values(by="Total_Profit", ascending=False).reset_index(drop=True)

    return aggregated

