            for pid in pids:
                try:
                    os.kill(pid, signal.SIGTERM)
                except OSError:
                    pass                                        
            time.sleep(1)
            return len(pids)

        else:                
            ps_output = subprocess.check_output(['ps', '-A', '-o', 'pid,comm'], text=True)
            lines = ps_output.strip().split('\n')
            pids = []
            for line in lines[1:]:
                parts = line.split(maxsplit=1)
                if len(parts) == 2 and parts[1].strip() == process_name:
                    try:
                        pids.append(int(parts[0]))
                    except ValueError:
                        continue

            for pid in pids:
                try:
                    os.kill(pid, signal.SIGTERM)
                except OSError:
                    pass                                        
            time.sleep(1)
            return len(pids)
    except subprocess.CalledProcessError:
        return 0
    except Exception:
        return 0

import subprocess
import os
import signal
import time
def task_func(process_name: str) -> int:
    try:
        result = subprocess.run(
            ["pgrep", "-f", process_name],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True
        )

        if result.returncode != 0 or not result.stdout.strip():
            return 0

        pids = [int(pid) for pid in result.stdout.strip().split("\n")]

        for pid in pids:
            try:
                os.kill(pid, signal.SIGTERM)
            except ProcessLookupError:
                continue

        time.sleep(1)

        return len(pids)

    except Exception as e:
        return 0

import subprocess
import os
import signal
import time
import psutil
def task_func(process_name: str) -> int:
    stopped_processes = 0
    for proc in psutil.process_iter(['pid', 'name']):
        if proc.info['name'] == process_name:
            try:
                os.kill(proc.info['pid'], signal.SIGTERM)
                time.sleep(1)
                if not psutil.pid_exists(proc.info['pid']):
                    stopped_processes += 1
            except (psutil.NoSuchProcess, OSError):
                pass
    return stopped_processes

