                print(f"Unexpected error processing file '{file_path}': {e}")

    if not failed_files:
        return {
            'success': True,
            'message': f"Successfully compressed and moved all files from '{src_folder}' to '{dst_folder}'.",
            'failed_files': []
        }
    else:
        return {
            'success': False,
            'message': f"Failed to compress or move some files. See 'failed_files' for details.",
            'failed_files': failed_files
        }

