ALPHABET = 'abcdefghijklmnopqrstuvwxyz'
def task_func(list_of_lists, seed=0):
    random.seed(seed)
    all_letters = []
    for inner_list in list_of_lists:
        if not inner_list:
            inner_list = random.sample(ALPHABET, random.randint(1, 10))
        all_letters.extend(inner_list)
