import matplotlib.pyplot as plt
def task_func(df):
    if not isinstance(df, pd.DataFrame):
        raise ValueError("Input must be a pandas DataFrame.")
    required_columns = {'Date', 'Time', 'Temperature'}
    if not required_columns.issubset(df.columns):
        raise ValueError(f"DataFrame must contain the following columns: {required_columns}")

    try:
        heatmap_data = df.pivot(index='Date', columns='Time', values='Temperature')
    except ValueError as e:
        raise ValueError("Error while pivoting the DataFrame. Ensure 'Date' and 'Time' have unique combinations.") from e

    plt.figure(figsize=(10, 8))
    ax = sns.heatmap(heatmap_data, annot=True, fmt=".1f", cmap="coolwarm", cbar_kws={'label': 'Temperature'})
    plt.title("Temperature Heatmap")
    plt.xlabel("Time")
    plt.ylabel("Date")
    plt.tight_layout()

    return ax

import pandas as pd
import os
def task_func(data_dir: str, csv_files: list) -> pd.DataFrame:
    if not csv_files:
        return pd.DataFrame()

    all_data = []
    for file in csv_files:
        file_path = os.path.join(data_dir, file)
        try:
            df = pd.read_csv(file_path)
            all_data.append(df)
        except FileNotFoundError:
