from datetime import datetime
import pytz
import re
from faker import Faker
import random
def task_func(epoch_milliseconds, seed=0, timezones=["UTC"]):
    faker = Faker()
    Faker.seed(seed)
    random.seed(seed)

    epoch_seconds = epoch_milliseconds / 1000
    local_datetime = datetime.fromtimestamp(epoch_seconds)

    valid_timezones = []
    for tz in timezones:
        if tz in pytz.all_timezones:
            valid_timezones.append(tz)
        else:
            if re.match(r"^UTC[+-](0[0-9]|1[0-4]):[0-5][0-9]$", tz):
                valid_timezones.append(tz)

    if not valid_timezones:
        selected_timezone = "UTC"
    else:
        selected_timezone = random.choice(valid_timezones)

    if selected_timezone in pytz.all_timezones:
        timezone = pytz.timezone(selected_timezone)
        localized_datetime = local_datetime.astimezone(timezone)
    else:
        match = re.match(r"^UTC([+-])(\d{2}):(\d{2})$", selected_timezone)
        if match:
            sign, hours, minutes = match.groups()
            offset = int(hours) * 60 + int(minutes)
            if sign == "-":
                offset = -offset
            timezone = pytz.FixedOffset(offset)
            localized_datetime = local_datetime.astimezone(timezone)

    event_name = faker.sentence(nb_words=3).strip(".")

    event_date = localized_datetime.strftime("%Y-%m-%d")
    event_time = localized_datetime.strftime("%H:%M:%S")

    event_schedule = {
        "date": event_date,
        "time": event_time,
        "timezone": selected_timezone
    }

    return {event_name: [event_schedule]}

from datetime import datetime
import pytz
import re
from faker import Faker
import random
def task_func(epoch_milliseconds, seed=0, timezones=["UTC"]):

    fake = Faker()
    fake.seed(seed)

    dt = datetime.fromtimestamp(epoch_milliseconds / 1000)

    event_name = fake.bs()

    valid_timezones = []

    for tz in timezones:
        if tz in pytz.all_timezones:
            valid_timezones.append(tz)
        elif re.match(r'^UTC([+-]\d{1,2}:\d{2})$', tz):
            valid_timezones.append(tz)

    if not valid_timezones:
        valid_timezones = ["UTC"]

    selected_tz = random.choice(valid_timezones)

    if selected_tz in pytz.all_timezones:
        tz = pytz.timezone(selected_tz)
    else:
        offset = selected_tz[3:]
        hours, minutes = map(int, offset.split(':'))
        if selected_tz[0] == '-':
            hours, minutes = -hours, -minutes
        tz = pytz.FixedOffset((hours * 60 + minutes) * 60)

    dt_tz = tz.localize(dt)

    schedule = {
        'date': dt_tz.strftime('%Y-%m-%d'),
        'time': dt_tz.strftime('%H:%M:%S'),
        'timezone': selected_tz
    }

    return {event_name: [schedule]}

import pandas as pd
from scipy.stats import pearsonr
import numpy as np
def task_func(data):
    if len(data) < 2:
        return np.nan

    try:
        data['score'] = data['score'].astype(float)
    except ValueError:
        return np.nan                                       

    grades = data['grade'].unique()
    grades_sorted = sorted(grades)
    grade_mapping = {grade: i for i, grade in enumerate(grades_sorted)}
    data['encoded_grade'] = data['grade'].map(grade_mapping)

    scores = data['score']
    encoded_grades = data['encoded_grade']

    try:
        correlation, _ = pearsonr(scores, encoded_grades)
        return correlation
    except ValueError:
        return np.nan

