            letter_counts[letter][j] += repetitions[j]

    fig, ax = plt.subplots()
    x = np.arange(len(letters))
    width = 0.2

    for i in range(len(repetitions)):
        counts = [letter_counts[letter][i] for letter in letters]
        ax.bar(x + (i * width), counts, width, label=f'Repetition {i+1}', color=colors[i])

    ax.set_xlabel('Letters')
    ax.set_ylabel('Frequency')
    ax.set_title('Frequency of Letters')
    ax.set_xticks(x + width * (len(repetitions) - 1) / 2)
    ax.set_xticklabels(letters)
    ax.legend()

    return ax

